const fs = require('fs');

const files = [
    'src/app/admin/news/page.tsx',
    'src/app/admin/events/page.tsx',
    'src/app/admin/academies/page.tsx',
    'src/app/admin/rankings/page.tsx',
    'src/app/admin/users/page.tsx'
];

files.forEach(file => {
    if (!fs.existsSync(file)) return;
    let content = fs.readFileSync(file, 'utf8');

    // Remove ALL rounded classes (e.g. rounded, rounded-lg, rounded-[40px]) global replacement including text inputs, modals, buttons.
    content = content.replace(/className="([^"]+)"/g, (match, classes) => {
        let newClasses = classes.split(/\s+/).filter(c => !c.startsWith('rounded')).join(' ');
        // Adjust heavy paddings that break small screens
        newClasses = newClasses.replace(/\bp-12\b/g, 'p-8').replace(/\bp-16\b/g, 'p-10');
        return `className="${newClasses}"`;
    });

    // Fix the modal structural cutoff by taking the FOOTER OUT of the `overflow-y-auto` block.
    // 1. We replace the start of the form area
    content = content.replace(
        /<div className="([^"]*overflow-y-auto custom-scrollbar flex-1[^"]*)">\s*<form([^>]*)>/g,
        '<form$2 className="flex flex-col flex-1 overflow-hidden">\n                            <div className="$1">'
    );

    // 2. We extract the footer block from the end of the scroll container
    content = content.replace(
        /<div className="([^"]*sticky bottom-0[^"]*)">([\s\S]*?)<\/div>\s*<\/form>\s*<\/div>/g,
        '</div>\n                            <div className="p-8 border-t border-silver-accent/20 bg-mist-white/30 shrink-0">$2</div>\n                        </form>'
    );

    fs.writeFileSync(file, content);
    console.log('Fixed', file);
});

const fs = require('fs');
const files = [
    'src/app/admin/news/page.tsx',
    'src/app/admin/events/page.tsx',
    'src/app/admin/academies/page.tsx',
    'src/app/admin/rankings/page.tsx',
    'src/app/admin/users/page.tsx'
];

files.forEach(file => {
    if (!fs.existsSync(file)) return;
    let c = fs.readFileSync(file, 'utf8');

    // 1. Fix duplicate className in form
    c = c.replace(/<form([^>]*) className="space-y-10"([^>]*) className="flex flex-col flex-1 overflow-hidden">/g,
        '<form$1$2 className="flex flex-col flex-1 overflow-hidden">');

    // 2. Add back the <div className="space-y-10"> wrapper inside the scroll container
    c = c.replace(/<div className="([^"]*overflow-y-auto custom-scrollbar flex-1[^"]*)">/g,
        '<div className="$1">\n                                <div className="space-y-10">');

    // 3. Add back the closing </div> for the space-y-10 wrapper right before the sticky footer is defined
    c = c.replace(/<\/div>\s*<div className="([^"]*shrink-0([^"]*))">/g,
        '</div>\n                            </div>\n                            <div className="$1">');

    fs.writeFileSync(file, c);
    console.log('Syntax fixed', file);
});

const mongoose = require('mongoose');

const MONGODB_URI = "mongodb://davidartaviarodriguez_db_user:UYUNlKLuR1rSoTsu@ac-cxc8kvq-shard-00-00.jodngjz.mongodb.net:27017,ac-cxc8kvq-shard-00-01.jodngjz.mongodb.net:27017,ac-cxc8kvq-shard-00-02.jodngjz.mongodb.net:27017/fecoka_web?ssl=true&replicaSet=atlas-p0tcts-shard-0&authSource=admin";

async function setAdmin() {
    try {
        console.log("Connecting to MongoDB Atlas...");
        await mongoose.connect(MONGODB_URI);
        console.log("Connected successfully!");

        // Assuming collection name is 'users' based on Mongoose default for model 'User'
        const db = mongoose.connection.db;
        const result = await db.collection('users').updateOne(
            { email: 'david.artavia.rodriguez@gmail.com' },
            { $set: { role: 'admin' } },
            { upsert: true } // If not exists, maybe we shouldn't upsert. Wait, upserting might miss other fields. But if the user logged in, they exist. Let's just update.
        );

        console.log(`Matched ${result.matchedCount} document(s) and modified ${result.modifiedCount} document(s).`);
        console.log("UpsertedId:", result.upsertedId);

        process.exit(0);
    } catch (error) {
        console.error("Error updating user:", error);
        process.exit(1);
    }
}

