import React from 'react';
import AdminSidebar from '@/components/admin/AdminSidebar';
import { redirect } from 'next/navigation';
import { auth } from '@/auth';

export default async function AdminLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const session = await auth();
    const user = session?.user as any;
    const userEmail = user?.email?.toLowerCase();
    const isSuperAdmin = userEmail === 'david.artavia.rodriguez@gmail.com';

    if (!session || (!isSuperAdmin && (user?.role !== 'admin' || user?.status !== 'active'))) {
        redirect('/');
    }

    return (
        <div className="flex flex-col md:flex-row h-[100dvh] bg-mist-white overflow-hidden text-deep-black font-sans">
            <AdminSidebar />
