import { MetadataRoute } from 'next'
import dbConnect from '@/lib/db'
import News from '@/models/News'
import Academy from '@/models/Academy'

export default async function sitemap(): Promise<MetadataRoute.Sitemap> {
    const baseUrl = 'https://fecoka.org'

    const staticRoutes = [
        '',
        '/news',
        '/events',
        '/rankings',
        '/academies',
        '/about',
    ].map((route) => ({
        url: `${baseUrl}${route}`,
        lastModified: new Date(),
        changeFrequency: 'daily' as const,
        priority: route === '' ? 1 : 0.8,
    }))

    // Vercel build phase doesn't have MONGODB_URI, return static only
    if (!process.env.MONGODB_URI) {
        return staticRoutes;
    }

    await dbConnect()

    // Fetch dynamic routes
    const [news, academies] = await Promise.all([
        News.find({}).select('_id updatedAt'),
        Academy.find({ isActive: true }).select('_id updatedAt')
    ])

    const newsRoutes = news.map((item) => ({
        url: `${baseUrl}/news/${item._id}`,
        lastModified: item.updatedAt || new Date(),
        changeFrequency: 'weekly' as const,
        priority: 0.7,
    }))

    const academyRoutes = academies.map((item) => ({
        url: `${baseUrl}/academies`, // Currently a single list page, but prepared for future detail pages
        lastModified: new Date(),
        changeFrequency: 'monthly' as const,
        priority: 0.6,
    }))

    return [...staticRoutes, ...newsRoutes, ...academyRoutes]
}

import Google from "next-auth/providers/google"
import type { NextAuthConfig } from "next-auth"

// This configuration only contains parts that are compatible with the Edge runtime
export default {
    debug: false,
    secret: process.env.AUTH_SECRET || process.env.NEXTAUTH_SECRET,
    providers: [
        Google({
            clientId: process.env.AUTH_GOOGLE_ID || process.env.GOOGLE_CLIENT_ID,
            clientSecret: process.env.AUTH_GOOGLE_SECRET || process.env.GOOGLE_CLIENT_SECRET,
        }),
    ],
    callbacks: {
        async session({ session, token }) {
            // Pass the role and ID from the JWT token to the client session object
            // This mapping is Edge-safe and required for middleware to see the role
            if (token && session.user) {
                (session.user as any).id = token.id as string;
                (session.user as any).role = token.role as string;
                (session.user as any).status = token.status as string;
            }
            return session;
        }
    }
} satisfies NextAuthConfig

import NextAuth from "next-auth"
import authConfig from "./auth.config"
import dbConnect from "@/lib/db"
import User from "@/models/User"
import { isSuperAdmin } from "@/lib/auth-utils"

export const { handlers, auth, signIn, signOut } = NextAuth({
    trustHost: true,
    ...authConfig,
    secret: process.env.AUTH_SECRET,
    callbacks: {
        ...authConfig.callbacks,
        async signIn({ user, profile }) {
            // We only use the Google provider, so the user is guaranteed to have a Google account.
            try {
                await dbConnect();

                // Find existing user or create a new one with 'user' role by default
                let dbUser = await User.findOne({ email: user.email });
                const isSystemAdmin = isSuperAdmin(user.email);

                if (!dbUser) {
                    dbUser = await User.create({
                        name: user.name,
                        email: user.email,
                        image: user.image,
                        role: isSystemAdmin ? 'admin' : 'user',
                        status: isSystemAdmin ? 'active' : 'pending',
                    });
                } else {
                    // Update last login
                    dbUser.lastLoginAt = new Date();
                    dbUser.name = user.name;
                    dbUser.image = user.image;

                    // Auto-admin for the main account
                    if (isSystemAdmin) {
                        dbUser.role = 'admin';
                        dbUser.status = 'active';
                    }

                    await dbUser.save();
                }

                return true;
            } catch (error: any) {
                console.error("====== VERIFICATION ERROR IN SIGN-IN ======");
                console.error("Error connecting to DB or creating user:", error?.message || error);
                console.error("Full error object:", error);
                console.error("===========================================");
                return false; // Prevent login if DB fails
            }
        },
        async jwt({ token, user, trigger }) {
            // When the user logs in, fetch their role from the DB and attach to token
            if (user) {
                await dbConnect();
                const dbUser = await User.findOne({ email: user.email });
                if (dbUser) {
                    token.id = dbUser._id.toString();
                    token.role = dbUser.role;
                    token.status = dbUser.status;
                }
            }
            return token;
        },
    },
    pages: {
        signIn: "/auth/signin", // Custom sign-in page/modal
    },
})

'use client';

import React from 'react';

interface ErrorBoundaryProps {
    children: React.ReactNode;
    fallback?: React.ReactNode;
}

interface ErrorBoundaryState {
    hasError: boolean;
}

export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
    constructor(props: ErrorBoundaryProps) {
        super(props);
        this.state = { hasError: false };
    }

    static getDerivedStateFromError(_: Error): ErrorBoundaryState {
        return { hasError: true };
    }

    componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
        console.error("ErrorBoundary caught an error", error, errorInfo);
        // Persist error for the render method to avoid generic [object Event]
        (this.state as any).errorDetails = error.message || String(error);
    }

    render() {
        if (this.state.hasError) {
            return this.props.fallback || (
                <div className="p-8 text-center bg-white rounded-[32px] border border-red-200 shadow-premium my-8">
                    <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6">
                        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                    </div>
                    <h2 className="text-2xl font-black text-midnight-blue mb-4">Ups! Algo salió mal.</h2>
                    <p className="text-steel-gray mb-2">Estamos teniendo dificultades para cargar esta sección.</p>
                    {(this.state as any).errorDetails && (
                        <p className="text-[10px] font-mono text-red-400 mb-6 bg-red-50 p-2 rounded overflow-hidden text-ellipsis">
                            Detalles: {(this.state as any).errorDetails}
                        </p>
                    )}
                    <button
                        onClick={() => {
                            this.setState({ hasError: false });
                            window.location.reload();
                        }}
                        className="bg-midnight-blue text-white px-8 py-3 font-bold hover:bg-crimson-red transition-colors shadow-lg"
                    >
                        Recargar Sitio
                    </button>
                </div>
            );
        }

        return this.props.children;
    }
}

