"use client";

import React, { useState, useMemo } from "react";
import { ChevronUp, ChevronDown, Search, Filter } from "lucide-react";
import { cn } from "@/lib/utils";

export type DataTableColumn<T> = {
    key: keyof T;
    header: string;
    sortable?: boolean;
    filterable?: boolean;
    render?: (value: any, row: T) => React.ReactNode;
    width?: string;
};

export type DataTableProps<T> = {
    data: T[];
    columns: DataTableColumn<T>[];
    className?: string;
    searchable?: boolean;
    searchPlaceholder?: string;
    itemsPerPage?: number;
    showPagination?: boolean;
    striped?: boolean;
    hoverable?: boolean;
    bordered?: boolean;
    compact?: boolean;
    loading?: boolean;
    emptyMessage?: string;
    onRowClick?: (row: T, index: number) => void;
};

export function DataTable<T extends Record<string, any>>({
    data,
    columns,
    className,
    searchable = true,
    searchPlaceholder = "Search...",
    itemsPerPage = 10,
    showPagination = true,
    striped = false,
    hoverable = true,
    bordered = true,
    compact = false,
    loading = false,
    emptyMessage = "No data available",
    onRowClick,
}: DataTableProps<T>) {
    const [search, setSearch] = useState("");
    const [sortConfig, setSortConfig] = useState<{
        key: keyof T | null;
        direction: "asc" | "desc";
    }>({ key: null, direction: "asc" });
    const [currentPage, setCurrentPage] = useState(1);
    const [columnFilters, setColumnFilters] = useState<Record<string, string>>(
        {},
    );

    // Filter data based on search and column filters
    const filteredData = useMemo(() => {
        let filtered = [...data];

        // Global search
        if (search) {
            filtered = filtered.filter((row) =>
                columns.some((column) => {
                    const value = row[column.key];
                    return value?.toString().toLowerCase().includes(search.toLowerCase());
                }),
            );
        }

        // Column filters
        Object.entries(columnFilters).forEach(([key, value]) => {
            if (value) {
                filtered = filtered.filter((row) => {
                    const rowValue = row[key as keyof T];
                    return rowValue
                        ?.toString()
                        .toLowerCase()
                        .includes(value.toLowerCase());
                });
            }
        });

        return filtered;
    }, [data, search, columnFilters, columns]);

    // Sort data
    const sortedData = useMemo(() => {
        if (!sortConfig.key) return filteredData;

        return [...filteredData].sort((a, b) => {
            const aValue = a[sortConfig.key!];
            const bValue = b[sortConfig.key!];

            if (aValue < bValue) {
                return sortConfig.direction === "asc" ? -1 : 1;
            }
            if (aValue > bValue) {
                return sortConfig.direction === "asc" ? 1 : -1;
            }
            return 0;
        });
    }, [filteredData, sortConfig]);

    // Pagination
    const paginatedData = useMemo(() => {
        if (!showPagination) return sortedData;

        const startIndex = (currentPage - 1) * itemsPerPage;
        return sortedData.slice(startIndex, startIndex + itemsPerPage);
    }, [sortedData, currentPage, itemsPerPage, showPagination]);

    const totalPages = Math.ceil(sortedData.length / itemsPerPage);

    const handleSort = (key: keyof T) => {
        setSortConfig((current) => ({
            key,
            direction:
                current.key === key && current.direction === "asc" ? "desc" : "asc",
        }));
    };

    const handleColumnFilter = (key: string, value: string) => {
        setColumnFilters((prev) => ({
            ...prev,
            [key]: value,
        }));
        setCurrentPage(1);
    };

    const clearColumnFilter = (key: string) => {
        setColumnFilters((prev) => {
            const newFilters = { ...prev };
            delete newFilters[key];
            return newFilters;
        });
    };
    if (loading) {
        return (
            <div className={cn("w-full bg-card", className)}>
                <div className="animate-pulse p-6">
                    {/* Search skeleton */}
                    {searchable && <div className="mb-6 h-11 bg-muted rounded-md"></div>}
                    {/* Table skeleton */}
                    <div className="border border-border  overflow-hidden">
                        <div className="bg-muted/30 h-14"></div>
                        {Array.from({ length: 5 }).map((_, i) => (
                            <div
                                key={i}
                                className="h-14 border-t border-border bg-card"
                            ></div>
                        ))}
                    </div>
                    {/* Pagination skeleton */}
                    <div className="mt-6 flex justify-between items-center">
                        <div className="h-4 bg-muted rounded w-48"></div>
                        <div className="flex gap-2">
                            <div className="h-9 w-20 bg-muted rounded-md"></div>
                            <div className="h-9 w-9 bg-muted rounded-md"></div>
                            <div className="h-9 w-9 bg-muted rounded-md"></div>
                            <div className="h-9 w-16 bg-muted rounded-md"></div>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div
            className={cn(
                "w-full bg-card",
                bordered && "border border-border",
                className,
            )}
        >
            {/* Search and Filters */}
            {searchable && (
                <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 p-4 border-b border-border">
                    <div className="relative w-full sm:w-auto sm:flex-1 sm:max-w-sm">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <input
                            type="text"
                            placeholder={searchPlaceholder}
                            value={search}
                            onChange={(e) => {
                                setSearch(e.target.value);
                                setCurrentPage(1);
                            }}
                            className="w-full pl-10 pr-4 py-2.5 border border-input rounded-md bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring focus:border-transparent transition-all"
                        />
                    </div>
                </div>
            )}
            {/* Table */}
            <div
                className={cn(
                    "overflow-hidden bg-muted/30",
                )}
            >
                <div className="overflow-x-auto">
                    <table className="w-full min-w-full">
                        <thead className="bg-muted/30">
                            <tr>
                                {columns.map((column) => (
                                    <th
                                        key={String(column.key)}
                                        className={cn(
                                            "text-left font-medium text-muted-foreground bg-muted/30",
                                            compact ? "px-4 py-3" : "px-6 py-4",
                                            column.sortable &&
                                            "cursor-pointer hover:bg-muted/50 transition-colors",
                                            column.width && `w-[${column.width}]`,
                                        )}
                                        onClick={() => column.sortable && handleSort(column.key)}
                                        style={column.width ? { width: column.width } : undefined}
                                    >
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-2">
                                                <span className="text-sm font-semibold">
                                                    {column.header}
                                                </span>
                                                {column.sortable && (
                                                    <div className="flex flex-col">
                                                        <ChevronUp
                                                            className={cn(
                                                                "h-3 w-3",
                                                                sortConfig.key === column.key &&
                                                                    sortConfig.direction === "asc"
                                                                    ? "text-primary"
                                                                    : "text-muted-foreground/40",
                                                            )}
                                                        />
                                                        <ChevronDown
                                                            className={cn(
                                                                "h-3 w-3 -mt-1",
                                                                sortConfig.key === column.key &&
                                                                    sortConfig.direction === "desc"
                                                                    ? "text-primary"
                                                                    : "text-muted-foreground/40",
                                                            )}
                                                        />
                                                    </div>
                                                )}
                                            </div>
                                            {column.filterable && (
                                                <div className="relative">
                                                    <Filter className="h-3 w-3 text-muted-foreground/50" />
                                                </div>
                                            )}
                                        </div>
                                        {/* Column Filter */}
                                        {column.filterable && (
                                            <div className="mt-3">
                                                <input
                                                    type="text"
                                                    placeholder="Filter..."
                                                    value={columnFilters[String(column.key)] || ""}
                                                    onChange={(e) =>
                                                        handleColumnFilter(
                                                            String(column.key),
                                                            e.target.value,
                                                        )
                                                    }
                                                    onClick={(e) => e.stopPropagation()}
                                                    className="w-full px-3 py-1.5 text-xs border border-input rounded-md bg-background focus:outline-none focus:ring-1 focus:ring-ring transition-all"
                                                />
                                                {columnFilters[String(column.key)] && (
                                                    <div className="absolute right-2 top-1 text-xs text-muted-foreground hover:text-foreground transition-colors cursor-pointer"
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            clearColumnFilter(String(column.key));
                                                        }}
                                                    >
                                                        ✕
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="bg-card">
                            {paginatedData.length === 0 ? (
                                <tr>
                                    <td
                                        colSpan={columns.length}
                                        className={cn(
                                            "text-center text-muted-foreground bg-card",
                                            compact ? "px-4 py-12" : "px-6 py-16",
                                        )}
                                    >
                                        <div className="flex flex-col items-center space-y-2">
                                            <div className="text-4xl">📊</div>
                                            <div className="font-medium">{emptyMessage}</div>
                                        </div>
                                    </td>
                                </tr>
                            ) : (
                                paginatedData.map((row, index) => (
                                    <tr
                                        key={index}
                                        className={cn(
                                            "border-t border-border bg-card transition-colors",
                                            striped && index % 2 === 0 && "bg-muted/20",
                                            hoverable && "hover:bg-muted/30",
                                            onRowClick && "cursor-pointer",
                                        )}
                                        onClick={() => onRowClick?.(row, index)}
                                    >
                                        {columns.map((column) => (
                                            <td
                                                key={String(column.key)}
                                                className={cn(
                                                    "text-sm text-foreground",
                                                    compact ? "px-4 py-3" : "px-6 py-4",
                                                )}
                                            >
                                                {column.render
                                                    ? column.render(row[column.key], row)
                                                    : String(row[column.key] ?? "")}
                                            </td>
                                        ))}
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
            {/* Pagination */}
            {showPagination && totalPages > 1 && (
                <div className="flex flex-col sm:flex-row items-center justify-between gap-4 p-4 bg-card border-t border-border">
                    <div className="text-sm text-muted-foreground order-2 sm:order-1">
                        Showing {(currentPage - 1) * itemsPerPage + 1} to{" "}
                        {Math.min(currentPage * itemsPerPage, sortedData.length)} of{" "}
                        {sortedData.length} results
                    </div>
                    <div className="flex items-center gap-2 order-1 sm:order-2">
                        <button
                            onClick={() => setCurrentPage((prev) => Math.max(prev - 1, 1))}
                            disabled={currentPage === 1}
                            className="px-3 py-2 text-sm border border-input rounded-md hover:bg-muted disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                        >
                            Previous
                        </button>
                        <div className="hidden sm:flex items-center gap-1">
                            {Array.from({ length: Math.min(totalPages, 5) }).map((_, i) => {
                                const pageNumber =
                                    currentPage <= 3
                                        ? i + 1
                                        : currentPage >= totalPages - 2
                                            ? totalPages - 4 + i
                                            : currentPage - 2 + i;

                                if (pageNumber < 1 || pageNumber > totalPages) return null;

                                return (
                                    <button
                                        key={pageNumber}
                                        onClick={() => setCurrentPage(pageNumber)}
                                        className={cn(
                                            "px-3 py-2 text-sm border border-input rounded-md hover:bg-muted transition-colors",
                                            currentPage === pageNumber &&
                                            "bg-primary text-primary-foreground border-primary hover:bg-primary/90",
                                        )}
                                    >
                                        {pageNumber}
                                    </button>
                                );
                            })}
                        </div>
                        <button
                            onClick={() =>
                                setCurrentPage((prev) => Math.min(prev + 1, totalPages))
                            }
                            disabled={currentPage === totalPages}
                            className="px-3 py-2 text-sm border border-input rounded-md hover:bg-muted disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                        >
                            Next
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

// 1. Import Dependencies
import * as React from 'react';
import { motion } from 'framer-motion';
import { ChevronRight, LogOut } from 'lucide-react';
import { cn } from '@/lib/utils';
import Link from 'next/link';

// 2. Define Prop Types
export interface NavItem {
    icon: React.ReactNode;
    label: string;
    href: string;
    isSeparator?: boolean; // Optional separator for grouping items
}

export interface UserProfile {
    name: string;
    email: string;
    avatarUrl: string;
    role?: string;
}

interface UserProfileSidebarProps {
    user: UserProfile;
    navItems: NavItem[];
    activeHref?: string;
    logoutItem: {
        icon: React.ReactNode;
        label: string;
        onClick: () => void;
    };
    onMenuItemClick?: () => void;
    className?: string;
}

// 3. Define Animation Variants
const sidebarVariants = {
    hidden: { opacity: 0 },
    visible: {
        opacity: 1,
        transition: {
            delayChildren: 0.2, // Small delay so the sidebar background slides in first
            staggerChildren: 0.1, // More noticeable waterfall stagger effect
        },
    },
} as const;

const itemVariants = {
    hidden: {
        opacity: 0,
        y: 40,        // Come from below
        rotate: 5     // Start with a slight angle (like the GSAP example)
    },
    visible: {
        opacity: 1,
        y: 0,
        rotate: 0,
        transition: {
            type: 'spring',
            stiffness: 110,
            damping: 14,
            mass: 0.8
        },
    },
} as const;

// 4. Create the Component
export const UserProfileSidebar = React.forwardRef<HTMLDivElement, UserProfileSidebarProps>(
    ({ user, navItems, activeHref, logoutItem, onMenuItemClick, className }, ref) => {
        return (
            <motion.aside
                ref={ref}
                className={cn(
                    'flex h-full w-full max-w-xs flex-col bg-mist-white shadow-premium border-r border-silver-accent font-sans overflow-hidden',
                    className
