import { useState, useCallback, useEffect } from 'react';

interface UseApiOptions<T> {
    initialData?: T;
    immediate?: boolean;
}

export function useApi<T>(
    url: string,
    options: UseApiOptions<T> = { immediate: true }
) {
    const [data, setData] = useState<T | undefined>(options.initialData);
    const [loading, setLoading] = useState<boolean>(!!options.immediate);
    const [error, setError] = useState<string | null>(null);

    const execute = useCallback(async (body?: any, customUrl?: string) => {
        setLoading(true);
        setError(null);
        try {
            const fetchUrl = customUrl || url;
            const fetchOptions: RequestInit = body ? {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
            } : { method: 'GET' };

            const response = await fetch(fetchUrl, fetchOptions);

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                throw new Error(errorData.error || `Error: ${response.status} ${response.statusText}`);
            }

            const result = await response.json();
            setData(result);
            return { data: result, error: null };
        } catch (err) {
            const message = err instanceof Error ? err.message : 'Error desconocido';
            setError(message);
            return { data: null, error: message };
        } finally {
            setLoading(false);
        }
    }, [url]);

    useEffect(() => {
        if (options.immediate) {
            execute();
        }
    }, [execute, options.immediate]);

    return { data, loading, error, execute, setData };
}

import { ADMIN_EMAILS, ROLES } from './constants';

/**
 * Checks if a user session has administrative privileges
 */
export function isAdmin(session: any): boolean {
    if (!session?.user) return false;

    // Check by role
    if (session.user.role === ROLES.ADMIN) return true;

    // Check by email (super-admin logic)
    if (session.user.email && ADMIN_EMAILS.includes(session.user.email.toLowerCase())) {
        return true;
    }

    return false;
}

/**
 * Checks if a user session has editor or admin privileges
 */
export function canEdit(session: any): boolean {
    if (!session?.user) return false;

    const role = session.user.role;
    return role === ROLES.ADMIN || role === ROLES.EDIT || isAdmin(session);
}

/**
 * Helper to determine if an email belongs to a super administrator
 */
export function isSuperAdmin(email?: string | null): boolean {
    if (!email) return false;
    return ADMIN_EMAILS.includes(email.toLowerCase());
}

import mongoose from 'mongoose';

/**
 * Global is used here to maintain a cached connection across hot reloads
 * in development. This prevents connections growing exponentially
 * during API Route usage.
 */
let cached = (global as any).mongoose;

if (!cached) {
  cached = (global as any).mongoose = { conn: null, promise: null };
}

async function dbConnect() {
  if (cached.conn) {
    return cached.conn;
  }

  if (!cached.promise) {
    const MONGODB_URI = process.env.MONGODB_URI;

    if (!MONGODB_URI) {
      throw new Error('Please define the MONGODB_URI environment variable inside .env.local or Vercel Settings');
    }

    const opts = {
      bufferCommands: false,
    };

    cached.promise = mongoose.connect(MONGODB_URI, opts).then((mongoose) => {
      return mongoose;
    });
  }
  cached.conn = await cached.promise;
  return cached.conn;
}

export default dbConnect;

